 " def to_dict ( self ) -> dict : """将Trade对象转换为字典格式。 Returns: - tid: 交易号 - eid: 委托号 - security: 证券代码 - price: 交易价格 - filled: 居交数量 - trade_fees: 交易手续费 - order_side: 交易方向 - time: 交易时间 """ return { "tid" : str ( self . tid ), "eid" : str ( self . eid ), "security" : self . security , "order_side" : str ( self . side ), "price" : self . price , "filled" : self . shares , "time" : self . time . isoformat (), "trade_fees" : self . fee , } def sell ( self , shares : float , price : float , fee : float , close_time : datetime . datetime ): """从当前未售出股中售出。 计算时将根据售出的股数，分摊买入和卖的交易成本。返回未售出的股份和未分摊的成本。 Args: shares: 待出售股数 price: 出售价格 fee: 交易手续费 close_time: 成交日期 """ assert self . side == EntrustSide . BUY if not self . closed : sec = self . security assert self . _unsell > 0 , str ( self ) + "状态错误，无法售出，请检查代码" sellable = min ( shares , self . _unsell ) # 计算本次交易的收益，并分摊交易成本 amortized_buy_fee = self . fee * sellable / self . shares amortized_sell_fee = fee * sellable / shares self . _unsell -= sellable self . _unamortized_fee -= amortized_buy_fee if self . _unsell == 0 : logger . debug ( "交易 %s ( %s )已close." , self . security , self . tid ) self . closed = True trade = Trade ( self . eid , sec , price , sellable , amortized_sell_fee , EntrustSide . SELL , close_time , ) tx = Transaction ( sec , self . time , close_time , self . price , price , sellable , amortized_buy_fee + amortized_sell_fee , ) return shares - sellable , fee - amortized_sell_fee , trade , tx
